// Get input from either Webhook or Google Form
const webhookData = $node["Webhook — Form Submission"]?.json || {};
const formData = $node["Google Forms Trigger"]?.json || {};

const headline = webhookData.headline || formData["Article Headline"] || formData["Headline"] || "";
const article_text = webhookData.article_text || formData["Article Text"] || formData["Content"] || headline;
const source_name = webhookData.source || formData["Source"] || "Unknown";

const kb = items.map(i => i.json);
const input = (headline || article_text).toLowerCase();

// RAG Matching Logic
const matches = kb.map(a => {
  const title = a["Source Name"] || a.title || "";
  const score = input.split(' ').filter(word => title.toLowerCase().includes(word) && word.length > 4).length;
  return { ...a, similarity_score: score };
}).sort((a, b) => b.similarity_score - a.similarity_score);

return matches.slice(0, 3).map(m => ({
  json: {
    ...m,
    orig_headline: headline,
    orig_text: article_text,
    orig_source: source_name
  }
}));

